diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 6e4689863407..bad5afea8547 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1317,6 +1317,7 @@ static Value *foldAndOrOfICmpsWithConstEq(ICmpInst *Cmp0, ICmpInst *Cmp1,
 /// or   (icmp Pred1 V1, C1) | (icmp Pred2 V2, C2)
 /// into a single comparison using range-based reasoning.
 /// NOTE: This is also used for logical and/or, must be poison-safe!
+
 Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
                                                      ICmpInst *ICmp2,
                                                      bool IsAnd) {
@@ -1338,6 +1339,14 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
       V2 = X;
   }

+  // Also look through 'and' with constant mask operations.
+  const APInt *Mask1 = nullptr, *Mask2 = nullptr;
+  Value *AndV1 = nullptr, *AndV2 = nullptr;
+  if (match(V1, m_And(m_Value(AndV1), m_APInt(Mask1))))
+    V1 = AndV1;
+  if (match(V2, m_And(m_Value(AndV2), m_APInt(Mask2))))
+    V2 = AndV2;
+
   if (V1 != V2)
     return nullptr;

@@ -1345,11 +1354,21 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
       IsAnd ? ICmpInst::getInverseCmpPredicate(Pred1) : Pred1, *C1);
   if (Offset1)
     CR1 = CR1.subtract(*Offset1);
+  if (Mask1) {
+    // For (V & Mask) == C, the range is [C, C + (-Mask))
+    // where -Mask = ~Mask + 1 (the number of values that match)
+    APInt RangeSize = -*Mask1;
+    CR1 = ConstantRange(CR1.getLower(), CR1.getLower() + RangeSize);
+  }

   ConstantRange CR2 = ConstantRange::makeExactICmpRegion(
       IsAnd ? ICmpInst::getInverseCmpPredicate(Pred2) : Pred2, *C2);
   if (Offset2)
     CR2 = CR2.subtract(*Offset2);
+  if (Mask2) {
+    APInt RangeSize = -*Mask2;
+    CR2 = ConstantRange(CR2.getLower(), CR2.getLower() + RangeSize);
+  }

   Type *Ty = V1->getType();
   Value *NewV = V1;
@@ -1384,6 +1403,7 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
   return Builder.CreateICmp(NewPred, NewV, ConstantInt::get(Ty, NewC));
 }

+
 /// Ignore all operations which only change the sign of a value, returning the
 /// underlying magnitude value.
 static Value *stripSignOnlyFPOps(Value *Val) {

